Here's a solid pattern using a custom `MockHttpMessageHandler` to control `HttpClient` behavior:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Reusable mock handler
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _handler;

        public MockHttpMessageHandler(
            Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
            => _handler = handler;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _handler(request, cancellationToken);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnErrorStatus()
    {
        var handler = new MockHttpMessageHandler((_, _) =>
            Task.FromResult(new HttpResponseMessage(
                System.Net.HttpStatusCode.InternalServerError)));

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        var handler = new MockHttpMessageHandler((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage());
        });

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<OperationCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        var handler = new MockHttpMessageHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct); // simulate slow server
            return new HttpResponseMessage();
        });

        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) };
        var fetcher = new DataFetcher(client);

        // HttpClient wraps timeout as TaskCanceledException
        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(3000)] // guard: fail the test if it hangs
    public async Task FetchAsync_CancellationDuringRead_Throws()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        var handler = new MockHttpMessageHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct); // will be cancelled
            return new HttpResponseMessage();
        });

        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }
}
```

**Key patterns:**

| Technique | Purpose |
|---|---|
| `MockHttpMessageHandler` | Avoids real HTTP; controls responses at the `HttpClient` transport level |
| Pre-cancelled `CancellationTokenSource` | Verifies the token is actually forwarded |
| `HttpClient.Timeout` | Tests the client-level timeout path (`TaskCanceledException`) |
| `CancellationTokenSource(delay)` | Simulates cancellation *during* an in-flight request |
| `[Timeout(3000)]` | Safety net so a broken test doesn't hang your CI indefinitely |

> **Tip:** `HttpClient` wraps timeouts as `TaskCanceledException`, *not* `TimeoutException`. In .NET 6+ you can inspect `TaskCanceledException.CancellationToken` to distinguish a timeout from an explicit cancellation—the timeout's token won't match the one you passed in.
